### New index.ts Structure

```typescript
import { Server } from '@modelcontextprotocol/sdk/server/index.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
import { CallToolRequestSchema, ListToolsRequestSchema } from '@modelcontextprotocol/sdk/types.js';

// Import tool modules
import { featureTools } from './tools/feature-tools.js';
import { agentTools } from './tools/agent-tools.js';
import { socialTools } from './tools/social-tools.js';
import { googleTools } from './tools/google-tools.js';
// ... (13 total imports)

// Import handler modules
import { handleFeatureTool } from './handlers/feature-handlers.js';
import { handleAgentTool } from './handlers/agent-handlers.js';
import { handleSocialTool } from './handlers/social-handlers.js';
import { handleGoogleTool } from './handlers/google-handlers.js';
// ... (15 total imports)

// Aggregate all tools into registry
const tools = [
  ...featureTools,
  ...agentTools,
  ...queueTools,
  ...contextTools,
  ...orchestrationTools,
  ...projectTools,
  ...gitTools,
  ...observabilityTools,
  ...contentTools,
  ...integrationTools,
  ...workspaceTools,
  ...setupTools,
  ...utilityTools,
  ...socialTools,      // NEW
  ...googleTools,      // NEW
];

// Route tool calls to appropriate handler module
async function handleTool(name: string, args: Record<string, unknown>) {
  // Dispatch to handler based on tool name
  if (featureTools.some(t => t.name === name)) return handleFeatureTool(name, args);
  if (agentTools.some(t => t.name === name)) return handleAgentTool(name, args);
  if (socialTools.some(t => t.name === name)) return handleSocialTool(name, args);
  if (googleTools.some(t => t.name === name)) return handleGoogleTool(name, args);
  // ... (15 total dispatch checks)

  throw new Error(`Unknown tool: ${name}`);
}

// Server setup (unchanged)
const server = new Server(
  { name: 'automaker-mcp-server', version: '1.0.0' },
  { capabilities: { tools: {} } }
);

server.setRequestHandler(ListToolsRequestSchema, async () => ({ tools }));
server.setRequestHandler(CallToolRequestSchema, async (request) => {
  const { name, arguments: args } = request.params;
  const result = await handleTool(name, args ?? {});
  return { content: [{ type: 'text', text: JSON.stringify(result, null, 2) }] };
});

const transport = new StdioServerTransport();
await server.connect(transport);
```

**Result:** `index.ts` reduced from **4,480 lines → ~200 lines** (96% reduction).

