### Handler Module Template

Each handler module contains the business logic for its tools:

```typescript
// packages/mcp-server/src/handlers/feature-handlers.ts
import { getApiBaseUrl, apiCall } from '../utils.js';

export async function handleFeatureTool(
  name: string,
  args: Record<string, unknown>
): Promise<unknown> {
  const apiUrl = getApiBaseUrl();

  switch (name) {
    case 'list_features': {
      const { status } = args;
      const endpoint = status ? `/features?status=${status}` : '/features';
      return apiCall(apiUrl, endpoint, 'GET');
    }

    case 'get_feature': {
      const { id } = args;
      if (!id) throw new Error('Feature ID is required');
      return apiCall(apiUrl, `/features/${id}`, 'GET');
    }

    // ... 4 more cases

    default:
      throw new Error(`Unknown feature tool: ${name}`);
  }
}
```

