import { getApiBaseUrl, apiCall } from '../utils.js';

export async function handleSocialTool(
  name: string,
  args: Record<string, unknown>
): Promise<unknown> {
  const apiUrl = getApiBaseUrl();

  switch (name) {
    case 'twitter_get_mentions': {
      const { since, limit = 20 } = args;
      return apiCall(apiUrl, '/social/twitter/mentions', 'POST', { since, limit });
    }

    case 'twitter_reply': {
      const { tweet_id, message } = args;
      if (!tweet_id || !message) throw new Error('tweet_id and message required');
      return apiCall(apiUrl, '/social/twitter/reply', 'POST', { tweet_id, message });
    }

    case 'youtube_get_comments': {
      const { video_id, limit = 20 } = args;
      return apiCall(apiUrl, '/social/youtube/comments', 'POST', { video_id, limit });
    }

    case 'youtube_reply_comment': {
      const { comment_id, message } = args;
      if (!comment_id || !message) throw new Error('comment_id and message required');
      return apiCall(apiUrl, '/social/youtube/reply', 'POST', { comment_id, message });
    }

    case 'substack_get_posts': {
      const { since, limit = 10 } = args;
      return apiCall(apiUrl, '/social/substack/posts', 'POST', { since, limit });
    }

    case 'substack_get_comments': {
      const { post_id } = args;
      if (!post_id) throw new Error('post_id required');
      return apiCall(apiUrl, '/social/substack/comments', 'POST', { post_id });
    }

    default:
      throw new Error(`Unknown social tool: ${name}`);
