import { getApiBaseUrl, apiCall } from '../utils.js';

export async function handleGoogleTool(
  name: string,
  args: Record<string, unknown>
): Promise<unknown> {
  const apiUrl = getApiBaseUrl();

  switch (name) {
    case 'gmail_list_messages': {
      const { query, max_results = 10 } = args;
      return apiCall(apiUrl, '/google/gmail/list', 'POST', { query, max_results });
    }

    case 'gmail_send_message': {
      const { to, subject, body } = args;
      if (!to || !subject || !body) throw new Error('to, subject, and body required');
      return apiCall(apiUrl, '/google/gmail/send', 'POST', { to, subject, body });
    }

    case 'calendar_list_events': {
      const { calendar_id = 'primary', time_min, time_max, max_results = 10 } = args;
      return apiCall(apiUrl, '/google/calendar/events', 'POST', {
        calendar_id, time_min, time_max, max_results
      });
    }

    case 'calendar_create_event': {
      const { calendar_id = 'primary', summary, start_time, end_time, description } = args;
      if (!summary || !start_time || !end_time) {
        throw new Error('summary, start_time, and end_time required');
      }
      return apiCall(apiUrl, '/google/calendar/create', 'POST', {
        calendar_id, summary, start_time, end_time, description
      });
    }

    case 'drive_list_files': {
      const { query, max_results = 10 } = args;
      return apiCall(apiUrl, '/google/drive/list', 'POST', { query, max_results });
    }

    case 'drive_upload_file': {
      const { name, content, folder_id } = args;
      if (!name || !content) throw new Error('name and content required');
      return apiCall(apiUrl, '/google/drive/upload', 'POST', { name, content, folder_id });
    }

    default:
      throw new Error(`Unknown Google tool: ${name}`);
  }
}
```

